// Helper: proxy POST to OpenAI
function proxyOpenAI(path, body, res) {
  const data = JSON.stringify(body);
  const options = {
    hostname: 'api.openai.com',
    path: path,
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(data)
    }
  };
  const req = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': apiRes.headers['content-type'] || 'application/json',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  req.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  req.write(data);
  req.end();
}

// Helper: proxy multipart (Whisper STT)
function proxyWhisper(reqBody, contentType, res) {
  const options = {
    hostname: 'api.openai.com',
    path: '/v1/audio/transcriptions',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': contentType,
      'Content-Length': reqBody.length
    }
  };
  const apiReq = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  apiReq.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  apiReq.write(reqBody);
  apiReq.end();
}

// Helper: proxy TTS (binary audio)
function proxyTTS(body, res) {
  const data = JSON.stringify(body);
  const options = {
    hostname: 'api.openai.com',
    path: '/v1/audio/speech',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(data)
    }
  };
  const req = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': 'audio/mpeg',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  req.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  req.write(data);
  req.end();
}

// Serve the HTML app + proxy routes
const server = createServer((req, res) => {
  // CORS preflight
  if (req.method === 'OPTIONS') {
    res.writeHead(204, {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'POST, GET, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization'
    });
    res.end();
    return;
  }

  // Proxy: Translation (GPT-4o)
  if (req.method === 'POST' && req.url === '/api/translate') {
    let body = '';
    req.on('data', d => body += d);
    req.on('end', () => {
      try { proxyOpenAI('/v1/chat/completions', JSON.parse(body), res); }
      catch(e) { res.writeHead(400); res.end(JSON.stringify({ error: e.message })); }
    });
    return;
  }

  // Proxy: TTS
  if (req.method === 'POST' && req.url === '/api/tts') {
    let body = '';
    req.on('data', d => body += d);
    req.on('end', () => {
      try { proxyTTS(JSON.parse(body), res); }
      catch(e) { res.writeHead(400); res.end(JSON.stringify({ error: e.message })); }
    });
    return;
  }

  // Proxy: Whisper STT
  if (req.method === 'POST' && req.url === '/api/stt') {
    const chunks = [];
    req.on('data', d => chunks.push(d));
    req.on('end', () => {
      const buf = Buffer.concat(chunks);
      proxyWhisper(buf, req.headers['content-type'], res);
    });
    return;
  }

  // Health check
  if (req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'ok', rooms: Object.keys(rooms).length }));
    return;
  }

  // Serve HTML app
  if (req.url === '/' || req.url === '/index.html') {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(HTML_CONTENT);
    return;
  }

  res.writeHead(404);
  res.end('Not found');
});

const wss = new WebSocketServer({ server });

// Rooms: { roomCode: { A: ws, B: ws } }
const rooms = {};

function generateCode() {
  return Math.floor(1000 + Math.random() * 9000).toString();
}

wss.on('connection', (ws) => {
  let myRoom = null;
  let mySide = null;

  ws.on('message', (data) => {
    let msg;
    try { msg = JSON.parse(data); } catch { return; }

    if (msg.type === 'create') {
      let code = generateCode();
      while (rooms[code]) code = generateCode();
      rooms[code] = { A: ws, B: null };
      myRoom = code;
      mySide = 'A';
      ws.send(JSON.stringify({ type: 'created', code }));
      console.log(`Room ${code} created`);
    }

    else if (msg.type === 'join') {
      const code = msg.code;
      if (!rooms[code]) {
        ws.send(JSON.stringify({ type: 'error', message: 'Λάθος κωδικός δωματίου' }));
        return;
      }
      if (rooms[code].B) {
        ws.send(JSON.stringify({ type: 'error', message: 'Το δωμάτιο είναι γεμάτο' }));
        return;
      }
      rooms[code].B = ws;
      myRoom = code;
      mySide = 'B';
      ws.send(JSON.stringify({ type: 'joined', code }));
      if (rooms[code].A && rooms[code].A.readyState === 1) {
        rooms[code].A.send(JSON.stringify({ type: 'partner_joined' }));
      }
      console.log(`Room ${code}: B joined`);
    }

    else if (msg.type === 'translation') {
      if (!myRoom || !rooms[myRoom]) return;
      const targetSide = mySide === 'A' ? 'B' : 'A';
      const target = rooms[myRoom][targetSide];
      if (target && target.readyState === 1) {
        target.send(JSON.stringify({
          type: 'play_translation',
          text: msg.text,
          voice: msg.voice,
          transcript: msg.transcript
        }));
      }
    }

    else if (msg.type === 'ping') {
      ws.send(JSON.stringify({ type: 'pong' }));
    }
  });

  ws.on('close', () => {
    if (!myRoom || !rooms[myRoom]) return;
    const other = mySide === 'A' ? 'B' : 'A';
    const otherWs = rooms[myRoom][other];
    if (otherWs && otherWs.readyState === 1) {
      otherWs.send(JSON.stringify({ type: 'partner_left' }));
    }
    rooms[myRoom][mySide] = null;
    if (!rooms[myRoom].A && !rooms[myRoom].B) {
      delete rooms[myRoom];
      console.log(`Room ${myRoom} deleted`);
    }
    console.log(`Room ${myRoom}: ${mySide} disconnected`);
  });

  ws.on('error', (err) => console.error('WS error:', err.message));
});

